changeSet.sql:
DO $$
BEGIN

    -- ── vehicle_media ──────────────────────────────────────────────────────

    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'vehicle_media' AND column_name = 'created_at') THEN
        ALTER TABLE vehicle_media ADD COLUMN created_at TIMESTAMP;
        UPDATE vehicle_media SET created_at = NOW() WHERE created_at IS NULL;
        ALTER TABLE vehicle_media ALTER COLUMN created_at SET NOT NULL;
    END IF;

    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'vehicle_media' AND column_name = 'updated_at') THEN
        ALTER TABLE vehicle_media ADD COLUMN updated_at TIMESTAMP;
        UPDATE vehicle_media SET updated_at = NOW() WHERE updated_at IS NULL;
        ALTER TABLE vehicle_media ALTER COLUMN updated_at SET NOT NULL;
    END IF;

    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'vehicle_media' AND column_name = 'deleted_at') THEN
        ALTER TABLE vehicle_media ADD COLUMN deleted_at TIMESTAMP;
    END IF;

    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'vehicle_media' AND column_name = 'created_by') THEN
        ALTER TABLE vehicle_media ADD COLUMN created_by VARCHAR(36);
    END IF;

    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'vehicle_media' AND column_name = 'updated_by') THEN
        ALTER TABLE vehicle_media ADD COLUMN updated_by VARCHAR(36);
    END IF;

    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'vehicle_media' AND column_name = 'deleted_by') THEN
        ALTER TABLE vehicle_media ADD COLUMN deleted_by VARCHAR(36);
    END IF;

    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'vehicle_media' AND column_name = 'is_deleted') THEN
        ALTER TABLE vehicle_media ADD COLUMN is_deleted BOOLEAN;
        UPDATE vehicle_media SET is_deleted = FALSE WHERE is_deleted IS NULL;
        ALTER TABLE vehicle_media ALTER COLUMN is_deleted SET NOT NULL;
        ALTER TABLE vehicle_media ALTER COLUMN is_deleted SET DEFAULT FALSE;
    END IF;

    -- ── vehicle_document ───────────────────────────────────────────────────

    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'vehicle_document' AND column_name = 'created_at') THEN
        ALTER TABLE vehicle_document ADD COLUMN created_at TIMESTAMP;
        UPDATE vehicle_document SET created_at = NOW() WHERE created_at IS NULL;
        ALTER TABLE vehicle_document ALTER COLUMN created_at SET NOT NULL;
    END IF;

    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'vehicle_document' AND column_name = 'updated_at') THEN
        ALTER TABLE vehicle_document ADD COLUMN updated_at TIMESTAMP;
        UPDATE vehicle_document SET updated_at = NOW() WHERE updated_at IS NULL;
        ALTER TABLE vehicle_document ALTER COLUMN updated_at SET NOT NULL;
    END IF;

    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'vehicle_document' AND column_name = 'deleted_at') THEN
        ALTER TABLE vehicle_document ADD COLUMN deleted_at TIMESTAMP;
    END IF;

    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'vehicle_document' AND column_name = 'created_by') THEN
        ALTER TABLE vehicle_document ADD COLUMN created_by VARCHAR(36);
    END IF;

    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'vehicle_document' AND column_name = 'updated_by') THEN
        ALTER TABLE vehicle_document ADD COLUMN updated_by VARCHAR(36);
    END IF;

    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'vehicle_document' AND column_name = 'deleted_by') THEN
        ALTER TABLE vehicle_document ADD COLUMN deleted_by VARCHAR(36);
    END IF;

    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'vehicle_document' AND column_name = 'is_deleted') THEN
        ALTER TABLE vehicle_document ADD COLUMN is_deleted BOOLEAN;
        UPDATE vehicle_document SET is_deleted = FALSE WHERE is_deleted IS NULL;
        ALTER TABLE vehicle_document ALTER COLUMN is_deleted SET NOT NULL;
        ALTER TABLE vehicle_document ALTER COLUMN is_deleted SET DEFAULT FALSE;
    END IF;

END $$;
